// --- Well-known configuration endpoint ---

app.get('/.well-known/oauth-authorization-server', (req, res) => {
  const baseUrl = `${req.protocol}://${req.get('host')}`;
  res.json({
    issuer: baseUrl,
    authorization_endpoint: `${baseUrl}/authorize`,
    token_endpoint: `${baseUrl}/token`,
    userinfo_endpoint: `${baseUrl}/userinfo`,
    introspection_endpoint: `${baseUrl}/introspect`,
    revocation_endpoint: `${baseUrl}/revoke`,
    response_types_supported: ['code'],
    grant_types_supported: ['authorization_code', 'refresh_token'],
    token_endpoint_auth_methods_supported: ['client_secret_basic', 'client_secret_post'],
    scopes_supported: ['openid', 'profile', 'email']
  });
});

// --- Client Registration Endpoint (admin only) ---

app.post('/register-client', (req, res) => {
  const authHeader = req.headers.authorization;
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'Authentication required.' });
  }

  const token = authHeader.slice(7);
  const tokenData = accessTokens[token];
  if (!tokenData || tokenData.expiresAt < Date.now() || tokenData.user.role !== 'admin') {
    return res.status(403).json({ error: 'Admin access required.' });
  }

  const { client_id, client_name, redirect_uris } = req.body;

  if (!client_id || !client_name || !redirect_uris || !Array.isArray(redirect_uris)) {
    return res.status(400).json({ error: 'client_id, client_name, and redirect_uris (array) are required.' });
  }

  if (registeredClients[client_id]) {
    return res.status(409).json({ error: 'Client ID already exists.' });
  }

  const clientSecret = crypto.randomBytes(32).toString('hex');

  registeredClients[client_id] = {
    client_id,
    client_secret: clientSecret,
    redirect_uris,
    name: client_name
  };

  res.status(201).json({
    client_id,
    client_secret: clientSecret,
    client_name,
    redirect_uris
  });
});

